import{_ as t,c as d,o as a,a4 as e}from"./chunks/framework.I1cCAST3.js";const g=JSON.parse('{"title":"终端操作","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/operations/index.md","filePath":"docs/terminal/operations/index.md"}'),r={name:"docs/terminal/operations/index.md"},o=e('<h1 id="终端操作" tabindex="-1">终端操作 <a class="header-anchor" href="#终端操作" aria-label="Permalink to &quot;终端操作&quot;">​</a></h1><p>终端是 Chaterm 的核心功能 -- 提供完整的 SSH 终端体验，支持分屏、搜索和键盘驱动的工作流。</p><h2 id="终端连接" tabindex="-1">终端连接 <a class="header-anchor" href="#终端连接" aria-label="Permalink to &quot;终端连接&quot;">​</a></h2><p>连接主机后，终端窗口会自动打开。终端支持：</p><ul><li><strong>全功能 SSH 终端</strong>：支持所有标准命令和操作。</li><li><strong>多标签管理</strong>：可以同时运行多个会话，并在它们之间切换。</li><li><strong>标签重命名</strong>：右键点击标签即可重命名，方便快速识别。</li><li><strong>标签克隆</strong>：可以在同一主机上复制当前会话。</li></ul><h2 id="终端分屏" tabindex="-1">终端分屏 <a class="header-anchor" href="#终端分屏" aria-label="Permalink to &quot;终端分屏&quot;">​</a></h2><p>分屏功能可以让您并排或上下查看多个会话。每个分屏窗格都是独立的终端会话，可以连接到不同的主机或运行不同的命令。</p><h3 id="分屏方法" tabindex="-1">分屏方法 <a class="header-anchor" href="#分屏方法" aria-label="Permalink to &quot;分屏方法&quot;">​</a></h3><ol><li>打开标签菜单栏或在终端内右键点击。</li><li>选择 <strong>向右分屏</strong> 或 <strong>向下分屏</strong>。</li><li>新的终端窗格会出现在选定的方向。</li><li>每个窗格独立运行 -- 可以单独输入命令、调整大小或关闭。</li></ol><h3 id="分屏快捷操作" tabindex="-1">分屏快捷操作 <a class="header-anchor" href="#分屏快捷操作" aria-label="Permalink to &quot;分屏快捷操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>向右分屏</td><td>通过标签菜单</td><td>通过标签菜单</td></tr><tr><td>向下分屏</td><td>通过标签菜单</td><td>通过标签菜单</td></tr><tr><td>克隆会话</td><td>通过标签菜单</td><td>通过标签菜单</td></tr></tbody></table><blockquote><p><strong>提示：</strong> 使用左右分屏可以在左侧查看日志、右侧执行命令。使用上下分屏可以在上方监控系统指标、下方进行操作。</p></blockquote><h2 id="终端搜索" tabindex="-1">终端搜索 <a class="header-anchor" href="#终端搜索" aria-label="Permalink to &quot;终端搜索&quot;">​</a></h2><p>在终端输出中搜索命令、错误信息或任何文本。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>按 <code>Cmd + F</code>（macOS）或 <code>Ctrl + F</code>（Windows/Linux）打开搜索栏。</li><li>输入搜索关键词。</li><li>匹配的文本会在终端输出中高亮显示。</li><li>点击 <strong>上一个</strong> / <strong>下一个</strong>（或使用箭头按钮）在匹配项之间跳转。</li><li>按 <code>Esc</code> 关闭搜索栏。</li></ol><h3 id="搜索快捷键" tabindex="-1">搜索快捷键 <a class="header-anchor" href="#搜索快捷键" aria-label="Permalink to &quot;搜索快捷键&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>打开搜索</td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td></tr><tr><td>关闭搜索</td><td><code>Esc</code></td><td><code>Esc</code></td></tr></tbody></table><h2 id="右键菜单操作" tabindex="-1">右键菜单操作 <a class="header-anchor" href="#右键菜单操作" aria-label="Permalink to &quot;右键菜单操作&quot;">​</a></h2><p>在终端任意位置右键点击可打开上下文菜单。</p><h3 id="剪贴板" tabindex="-1">剪贴板 <a class="header-anchor" href="#剪贴板" aria-label="Permalink to &quot;剪贴板&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th><th>描述</th></tr></thead><tbody><tr><td><strong>复制</strong></td><td><code>Cmd + C</code></td><td><code>Ctrl + C</code></td><td>复制选中的文本</td></tr><tr><td><strong>粘贴</strong></td><td><code>Cmd + V</code></td><td><code>Ctrl + V</code></td><td>粘贴剪贴板内容</td></tr></tbody></table><h3 id="显示" tabindex="-1">显示 <a class="header-anchor" href="#显示" aria-label="Permalink to &quot;显示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th><th>描述</th></tr></thead><tbody><tr><td><strong>搜索</strong></td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td><td>打开搜索栏</td></tr><tr><td><strong>清屏</strong></td><td>通过右键菜单</td><td>通过右键菜单</td><td>清除终端可见输出</td></tr><tr><td><strong>字体大小</strong></td><td>通过右键菜单</td><td>通过右键菜单</td><td>放大或缩小终端字体</td></tr></tbody></table><h3 id="连接" tabindex="-1">连接 <a class="header-anchor" href="#连接" aria-label="Permalink to &quot;连接&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>断开连接</strong></td><td>断开当前 SSH 连接</td></tr><tr><td><strong>新终端</strong></td><td>打开新的终端会话</td></tr><tr><td><strong>关闭终端</strong></td><td>关闭当前终端会话</td></tr></tbody></table><h3 id="分屏" tabindex="-1">分屏 <a class="header-anchor" href="#分屏" aria-label="Permalink to &quot;分屏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>向右分屏</strong></td><td>创建水平分屏窗格</td></tr><tr><td><strong>向下分屏</strong></td><td>创建垂直分屏窗格</td></tr></tbody></table><h2 id="所有键盘快捷键" tabindex="-1">所有键盘快捷键 <a class="header-anchor" href="#所有键盘快捷键" aria-label="Permalink to &quot;所有键盘快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>复制</td><td><code>Cmd + C</code></td><td><code>Ctrl + C</code></td></tr><tr><td>粘贴</td><td><code>Cmd + V</code></td><td><code>Ctrl + V</code></td></tr><tr><td>搜索</td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td></tr><tr><td>AI 命令对话框</td><td><code>Cmd + K</code></td><td><code>Ctrl + K</code></td></tr><tr><td>AI 侧边栏</td><td><code>Cmd + L</code></td><td><code>Ctrl + L</code></td></tr></tbody></table><p>完整快捷键列表请参阅 <a href="/docs/settings/shortcuts/">快捷键设置</a>。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/terminal/manage/">终端管理</a> -- 标签页、克隆和关闭会话。</li><li><a href="/docs/settings/shortcuts/">快捷键设置</a> -- 查看和自定义所有键盘快捷键。</li></ul>',33),h=[o];function l(i,n,s,c,b,u){return a(),d("div",null,h)}const x=t(r,[["render",l]]);export{g as __pageData,x as default};
